Home Fragrance Advertisement

Prompt: 
{
  "Objective": "Create a refined 2×2 grid advertisement for the luxury home fragrance 'AERÉON', emphasizing mood, atmosphere, and sensory elegance through minimal, editorial-style visuals.",
  "Canvas": {
    "Aspect_Ratio": "1:1",
    "Grid_Structure": "2×2 equal panels",
    "Orientation": "Square",
    "Use_Case": [
      "Luxury brand social media",
      "Home & lifestyle campaigns",
      "E-commerce product storytelling",
      "Editorial-style digital ads"
    ]
  },
  "Panels": [
    {
      "Panel_Number": 1,
      "Title": "Hero Fragrance Object",
      "Description": "Studio hero shot of the AERÉON fragrance bottle centered on a stone or wood surface.",
      "Visual_Details": {
        "Lighting": "Soft diffused light with gentle shadows",
        "Background": "Neutral warm tones linen",
        "Focus": "Bottle shape, glass quality, minimalist label",
        "Mood": ["Elegance", "Calm", "Premium"]
      }
    },
    {
      "Panel_Number": 2,
      "Title": "Atmospheric Interior",
      "Description": "Lifestyle interior scene with the fragrance placed on a shelf or table.",
      "Visual_Details": {
        "Setting": "Modern, serene living space",
        "Lighting": "Natural window light",
        "Mood": ["Comfort", "Warmth", "Refined living"]
      }
    },
    {
      "Panel_Number": 3,
      "Title": "Scent Ritual Detail",
      "Description": "Close-up of hands interacting with the fragrance (spraying or opening).",
      "Visual_Details": {
        "Focus": "Human interaction and ritual",
        "Depth_of_Field": "Shallow and intimate",
        "Mood": ["Sensory", "Personal", "Mindful"]
      }
    },
    {
      "Panel_Number": 4,
      "Title": "Material & Mood",
      "Description": "Macro or still-life composition featuring fragrance alongside natural elements.",
      "Visual_Details": {
        "Elements": ["Stone", "Linen", "Wood", "Ceramic"],
        "Lighting": "Soft highlights, low contrast",
        "Mood": ["Natural", "Timeless", "Atmospheric"]
      }
    }
  ],
  "Branding": {
    "Product_Name": "AERÉON",
    "Brand_Personality": "Quiet luxury, modern, sensory-focused",
    "Color_Palette": ["Warm Beige", "Soft Taupe", "Smoked Glass"],
    "Logo_Presentation": "Minimal, understated, centered or embossed"
  },
  "Visual_Style": {
    "Style_Keywords": [
      "Luxury home lifestyle advertising",
      "Editorial still-life photography",
      "Minimalist composition",
      "High realism",
      "Soft natural tones"
    ]
  },
  "Camera_And_Lighting": {
    "Photography_Type": "Editorial and commercial hybrid photography",
    "Shot_Types": [
      "Hero product shot",
      "Interior lifestyle shot",
      "Macro detail",
      "Still-life composition"
    ],
    "Lighting_Style": "Natural window light with soft diffusion",
    "Exposure": "Low contrast, warm, balanced",
    "Shadows": "Soft and organic"
  },
  "Mood_Keywords": [
    "Calm",
    "Refined",
    "Atmospheric",
    "Elegant",
    "Warm",
    "Sensory"
  ],
  "Negative_Prompt": [
    "Harsh lighting",
    "Cluttered interiors",
    "Cheap glass appearance",
    "Bold or loud colors",
    "Unreadable labels",
    "CGI or artificial look",
    "Over-styling",
    "Watermarks",
    "Text overlays"
  ]
}

